import React, { useRef, useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { createRoot } from 'react-dom/client';
import clsx from 'clsx';

import Button, { ButtonListContainer } from '@components/ui/Button';

import { ifrm, hiden } from './customIframe.module.css';

// We do not rely on 'ref' property to get handle to iframe since in firefox it doesn't work
// instead we use onLoad() handler to get the handle to iframe body
// we may choose to combine both techniues
// https://stackoverflow.com/questions/70158165/react-iframe-createportal-doesnt-work-in-firefox
// https://github.com/facebook/react/issues/22847
// Example implementation -- https://github.com/Automattic/woocommerce-payments/pull/4093/commits/ea2cfe6eda5bf5b72054ec6213961b93d4cd35ab
/*--------------------------------------+
	USING REFS to get iFrame handle		|
---------------------------------------*/
/*--------------------------+
	USING createPortal()	|
---------------------------*/
//https://blog.logrocket.com/best-practices-react-iframes/
//https://github.com/ryanseddon/react-frame-component
export default function CustomIframe({ title, children, cssString, isHiddenOnScreen, showPrintButton, printBtnText, ...props }) {
	const [mountNode, setMountNode] = useState(null);
	const iframeRef = useRef(null);

	const printIframe = () => {
		iframeRef.current && iframeRef.current?.contentWindow.print();
	};

	const doOnIframeLoad = (e) => {
		//we use onLoad to get handle to iframe body, since in firefox relying on ref to get the handle fails
		const iframeElm = e.target;
		if (!iframeElm?.contentDocument) return;
		setMountNode(iframeElm?.contentDocument.body);

		//iFrame title
		if (title && iframeElm.contentDocument) {
			iframeElm.contentDocument.title = title;
		}
		//inject custom css
		if (cssString) {
			const iframeHead = iframeElm.contentDocument?.head;
			if (iframeHead) {
				const s = document.createElement('STYLE');
				s.setAttribute('type', 'text/css');
				s.textContent = cssString; //'body{background:#f00}';
				iframeHead.appendChild(s);
			}
		}
	};

	useEffect(() => {
		if (iframeRef.current !== null) {
			// var mountNode = iframeRef?.current?.contentWindow?.document?.body;
			// setMountNode(iframeRef?.current?.contentWindow?.document?.body);
			if (!mountNode) setMountNode(iframeRef.current?.contentDocument?.body); //same as above
			//iFrame title
			if (title && iframeRef.current?.contentDocument) {
				iframeRef.current.contentDocument.title = title;
			}
			//inject custom css
			if (cssString) {
				const iframeHead = iframeRef.current?.contentDocument?.head;
				if (iframeHead) {
					const s = document.createElement('STYLE');
					s.setAttribute('type', 'text/css');
					s.textContent = cssString; //'body{background:#f00}';
					iframeHead.appendChild(s);
				}
			}
		}

		//cleanup
		return () => {
			setMountNode(null);
		};
	}, [iframeRef]);

	return (
		<>
			<iframe ref={iframeRef} onLoad={doOnIframeLoad} className={clsx(ifrm, isHiddenOnScreen && hiden)} {...props}>
				{mountNode && createPortal(children, mountNode)}
			</iframe>
			{(showPrintButton || isHiddenOnScreen) && (
				<ButtonListContainer>
					<Button variant="primary" size="small" onClick={printIframe} icon="printer" isIconOnRight={false}>
						{printBtnText || 'Print'}
					</Button>
				</ButtonListContainer>
			)}
		</>
	);
} //*/

